<body>
  <main class="app">
    <section class="hud" aria-label="Game information">
      <div>
        <h1>Snake</h1>
        <p class="subtitle">Arrow keys move. Avoid walls and your tail.</p>
      </div>
      <div class="badge-row">
        <div class="badge">
          <span class="label">Score</span>
          <span class="value" id="score">0</span>
        </div>
        <div class="badge">
          <span class="label">Best</span>
          <span class="value" id="best-score">0</span>
        </div>
      </div>
    </section>

    <section class="game-shell" aria-label="Snake board">
      <canvas id="game" width="600" height="600" aria-label="Snake game board" role="img"></canvas>
      <div class="overlay visible" id="overlay" aria-live="polite">
        <div class="overlay-panel">
          <h2 id="overlay-title">Ready?</h2>
          <p class="game-over-copy" id="overlay-copy">Press start, then use the arrow keys to steer.</p>
          <div class="actions">
            <button id="primary-action" type="button">Start Game</button>
          </div>
        </div>
      </div>
    </section>

    <section class="footer">
      <p class="helper">Press space to restart after a game over.</p>
      <button class="secondary" id="restart-button" type="button">Restart</button>
    </section>
  </main>

  <script>
    const canvas = document.getElementById("game");
    const ctx = canvas.getContext("2d");
    const overlay = document.getElementById("overlay");
    const overlayTitle = document.getElementById("overlay-title");
    const overlayCopy = document.getElementById("overlay-copy");
    const primaryAction = document.getElementById("primary-action");
    const restartButton = document.getElementById("restart-button");
    const scoreEl = document.getElementById("score");
    const bestScoreEl = document.getElementById("best-score");

    const gridSize = 20;
    const cellCount = 20;
    const boardSize = gridSize * cellCount;
    const stepMs = 120;
    const bestScoreKey = "snake-best-score";

    let snake;
    let direction;
    let nextDirection;
    let food;
    let score;
    let bestScore = Number.parseInt(localStorage.getItem(bestScoreKey) || "0", 10);
    let playing = false;
    let gameOver = false;
    let lastTick = 0;
    let rafId;

    canvas.width = boardSize;
    canvas.height = boardSize;
    bestScoreEl.textContent = String(bestScore);

    function resetGame() {
      snake = [
        { x: 10, y: 10 },
        { x: 9, y: 10 },
        { x: 8, y: 10 }
      ];
      direction = { x: 1, y: 0 };
      nextDirection = { x: 1, y: 0 };
      score = 0;
      playing = false;
      gameOver = false;
      lastTick = 0;
      spawnFood();
      updateScore();
      showOverlay("Ready?", "Press start, then use the arrow keys to steer.", "Start Game");
      draw();
    }

    function startGame() {
      if (playing) {
        return;
      }

      playing = true;
      gameOver = false;
      hideOverlay();
      cancelAnimationFrame(rafId);
      rafId = requestAnimationFrame(loop);
    }

    function endGame() {
      playing = false;
      gameOver = true;
      updateBestScore();
      showOverlay("Game Over", `Final score: ${score}. Press restart or hit space to play again.`, "Play Again");
    }

    function showOverlay(title, copy, actionLabel) {
      overlayTitle.textContent = title;
      overlayCopy.textContent = copy;
      primaryAction.textContent = actionLabel;
      overlay.classList.add("visible");
    }

    function hideOverlay() {
      overlay.classList.remove("visible");
    }

    function updateScore() {
      scoreEl.textContent = String(score);
    }

    function updateBestScore() {
      if (score <= bestScore) {
        return;
      }

      bestScore = score;
      localStorage.setItem(bestScoreKey, String(bestScore));
      bestScoreEl.textContent = String(bestScore);
    }

    function spawnFood() {
      do {
        food = {
          x: Math.floor(Math.random() * cellCount),
          y: Math.floor(Math.random() * cellCount)
        };
      } while (snake && snake.some((segment) => segment.x === food.x && segment.y === food.y));
    }

    function loop(timestamp) {
      if (!playing) {
        return;
      }

      if (!lastTick) {
        lastTick = timestamp;
      }

      const elapsed = timestamp - lastTick;
      if (elapsed >= stepMs) {
        update();
        lastTick = timestamp;
      }

      draw();
      rafId = requestAnimationFrame(loop);
    }

    function update() {
      direction = nextDirection;
      const head = snake[0];
      const newHead = {
        x: head.x + direction.x,
        y: head.y + direction.y
      };

      const hitWall =
        newHead.x < 0 ||
        newHead.x >= cellCount ||
        newHead.y < 0 ||
        newHead.y >= cellCount;

      const hitSelf = snake.some((segment) => segment.x === newHead.x && segment.y === newHead.y);

      if (hitWall || hitSelf) {
        endGame();
        draw();
        return;
      }

      snake.unshift(newHead);

      if (newHead.x === food.x && newHead.y === food.y) {
        score += 1;
        updateScore();
        spawnFood();
      } else {
        snake.pop();
      }
    }

    function draw() {
      drawBoard();
      drawFood();
      drawSnake();
    }

    function drawBoard() {
      ctx.clearRect(0, 0, boardSize, boardSize);

      for (let y = 0; y < cellCount; y += 1) {
        for (let x = 0; x < cellCount; x += 1) {
          ctx.fillStyle = (x + y) % 2 === 0 ? getCssVar("--grid-a") : getCssVar("--grid-b");
          ctx.fillRect(x * gridSize, y * gridSize, gridSize, gridSize);
        }
      }
    }

    function drawSnake() {
      snake.forEach((segment, index) => {
        const inset = index === 0 ? 1 : 2;
        const size = index === 0 ? gridSize - 2 : gridSize - 4;
        ctx.fillStyle = index === 0 ? getCssVar("--accent") : getCssVar("--accent-strong");
        ctx.fillRect(
          segment.x * gridSize + inset,
          segment.y * gridSize + inset,
          size,
          size
        );
      });
    }

    function drawFood() {
      ctx.fillStyle = getCssVar("--food");
      ctx.beginPath();
      ctx.arc(
        food.x * gridSize + gridSize / 2,
        food.y * gridSize + gridSize / 2,
        gridSize / 2.8,
        0,
        Math.PI * 2
      );
      ctx.fill();
    }

    function getCssVar(name) {
      return getComputedStyle(document.documentElement).getPropertyValue(name).trim();
    }

    function handleDirectionChange(event) {
      const keyMap = {
        ArrowUp: { x: 0, y: -1 },
        ArrowDown: { x: 0, y: 1 },
        ArrowLeft: { x: -1, y: 0 },
        ArrowRight: { x: 1, y: 0 }
      };

      const proposed = keyMap[event.key];

      if (!proposed) {
        if (event.code === "Space" && gameOver) {
          event.preventDefault();
          resetGame();
          startGame();
        }
        return;
      }

      event.preventDefault();

      const reversing =
        proposed.x === -direction.x &&
        proposed.y === -direction.y;

      if (reversing) {
        return;
      }

      nextDirection = proposed;

      if (!playing && !gameOver) {
        startGame();
      }
    }

    primaryAction.addEventListener("click", () => {
      if (gameOver) {
        resetGame();
      }
      startGame();
    });

    restartButton.addEventListener("click", () => {
      resetGame();
      startGame();
    });

    window.addEventListener("keydown", handleDirectionChange);

    resetGame();
  </script>
